# comms_effectiveness.py — track engagement metrics for communications cadence

from dataclasses import dataclass
from typing import List, Dict
from datetime import date

@dataclass
class CommunicationMetrics:
    communication_type: str
    audience_segment: str
    send_date: date
    recipients: int
    opens: int = 0
    clicks: int = 0
    meeting_invitees: int = 0
    meeting_attendees: int = 0
    survey_responses: int = 0

    @property
    def open_rate(self) -> float:
        return self.opens / self.recipients if self.recipients else 0.0

    @property
    def click_rate(self) -> float:
        return self.clicks / self.opens if self.opens else 0.0

    @property
    def attendance_rate(self) -> float:
        return self.meeting_attendees / self.meeting_invitees if self.meeting_invitees else 0.0

    def is_below_threshold(self) -> bool:
        if self.recipients > 0:
            return self.open_rate < 0.4  # Flag if under 40% open rate
        if self.meeting_invitees > 0:
            return self.attendance_rate < 0.6  # Flag if under 60% attendance
        return False

def analyse_cadence_effectiveness(
    metrics: List[CommunicationMetrics]
) -> Dict[str, List[CommunicationMetrics]]:
    by_segment = {}
    for m in metrics:
        if m.audience_segment not in by_segment:
            by_segment[m.audience_segment] = []
        by_segment[m.audience_segment].append(m)

    report = {}
    for segment, items in by_segment.items():
        below_threshold = [m for m in items if m.is_below_threshold()]
        report[segment] = {
            "total_communications": len(items),
            "below_threshold_count": len(below_threshold),
            "below_threshold_items": [m.communication_type for m in below_threshold],
            "avg_open_rate": sum(m.open_rate for m in items if m.recipients > 0) / max(1, len(items)),
        }
    return report
